// src/pages/Categories.js
import React, { useEffect, useState } from 'react';
import api from '../utils/api';

const COLORS  = ['#f59e0b','#ef4444','#3b82f6','#10b981','#8b5cf6','#06b6d4','#f97316','#84cc16'];
const ICONS   = ['📁','🍔','✈️','💡','🛍️','💊','📚','🎮','🚗','🏠','💼','🎵'];

export default function Categories() {
  const [categories, setCategories] = useState([]);
  const [form, setForm]             = useState({ name: '', color: '#6366f1', icon: '📁' });
  const [loading, setLoading]       = useState(false);
  const [error, setError]           = useState('');

  const fetchCategories = async () => {
    const res = await api.get('/categories');
    setCategories(res.data);
  };

  useEffect(() => { fetchCategories(); }, []);

  const handleAdd = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await api.post('/categories', form);
      setForm({ name: '', color: '#6366f1', icon: '📁' });
      fetchCategories();
    } catch (err) {
      setError('Failed to add category.');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this category?')) return;
    try {
      await api.delete(`/categories/${id}`);
      fetchCategories();
    } catch (err) {
      alert(err.response?.data?.message || 'Cannot delete predefined category.');
    }
  };

  const predefined = categories.filter((c) => c.user_id === null);
  const custom     = categories.filter((c) => c.user_id !== null);

  return (
    <div>
      <h4 className="fw-bold mb-4">Categories</h4>

      <div className="row g-4">
        {/* Add custom category */}
        <div className="col-lg-4">
          <div className="table-card p-3">
            <h6 className="fw-bold mb-3">Create Custom Category</h6>
            {error && <div className="alert alert-danger py-2">{error}</div>}
            <form onSubmit={handleAdd}>
              <div className="mb-3">
                <label className="form-label">Name</label>
                <input type="text" className="form-control" maxLength={100} required
                  placeholder="e.g. Gym"
                  value={form.name}
                  onChange={(e) => setForm((p) => ({ ...p, name: e.target.value }))} />
              </div>

              <div className="mb-3">
                <label className="form-label">Icon</label>
                <div className="d-flex flex-wrap gap-2">
                  {ICONS.map((ic) => (
                    <button key={ic} type="button"
                      className={`btn btn-sm ${form.icon === ic ? 'btn-primary' : 'btn-outline-secondary'}`}
                      style={{ fontSize: '1.1rem', padding: '4px 8px' }}
                      onClick={() => setForm((p) => ({ ...p, icon: ic }))}>
                      {ic}
                    </button>
                  ))}
                </div>
              </div>

              <div className="mb-3">
                <label className="form-label">Color</label>
                <div className="d-flex flex-wrap gap-2">
                  {COLORS.map((col) => (
                    <button key={col} type="button"
                      onClick={() => setForm((p) => ({ ...p, color: col }))}
                      style={{
                        width: '28px', height: '28px', borderRadius: '50%',
                        background: col, border: form.color === col ? '3px solid #1e1b4b' : '2px solid #e2e8f0',
                        cursor: 'pointer',
                      }} />
                  ))}
                  <input type="color" className="form-control form-control-color"
                    style={{ width: '28px', height: '28px', borderRadius: '50%', padding: 0, cursor: 'pointer' }}
                    value={form.color}
                    onChange={(e) => setForm((p) => ({ ...p, color: e.target.value }))} />
                </div>
              </div>

              <button type="submit" className="btn btn-primary btn-sm w-100"
                disabled={loading} style={{ background: 'var(--primary)', border: 'none' }}>
                {loading ? 'Adding…' : '+ Add Category'}
              </button>
            </form>
          </div>
        </div>

        {/* Category lists */}
        <div className="col-lg-8">
          <div className="table-card p-3 mb-3">
            <h6 className="fw-bold mb-3">Predefined Categories</h6>
            <div className="row g-2">
              {predefined.map((cat) => (
                <div key={cat.id} className="col-sm-6">
                  <div className="d-flex align-items-center gap-2 p-2 rounded"
                    style={{ border: '1px solid #e2e8f0', background: '#fafafa' }}>
                    <span style={{
                      width: '32px', height: '32px', borderRadius: '8px',
                      background: cat.color + '20', display: 'flex',
                      alignItems: 'center', justifyContent: 'center', fontSize: '1rem',
                    }}>{cat.icon}</span>
                    <span style={{ fontWeight: 600, fontSize: '0.88rem' }}>{cat.name}</span>
                    <span className="ms-auto badge" style={{ background: cat.color, color: '#fff', fontSize: '0.7rem' }}>
                      Built-in
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {custom.length > 0 && (
            <div className="table-card p-3">
              <h6 className="fw-bold mb-3">My Custom Categories</h6>
              <div className="row g-2">
                {custom.map((cat) => (
                  <div key={cat.id} className="col-sm-6">
                    <div className="d-flex align-items-center gap-2 p-2 rounded"
                      style={{ border: '1px solid #e2e8f0', background: '#fafafa' }}>
                      <span style={{
                        width: '32px', height: '32px', borderRadius: '8px',
                        background: cat.color + '20', display: 'flex',
                        alignItems: 'center', justifyContent: 'center', fontSize: '1rem',
                      }}>{cat.icon}</span>
                      <span style={{ fontWeight: 600, fontSize: '0.88rem' }}>{cat.name}</span>
                      <button className="btn btn-sm btn-outline-danger ms-auto py-0 px-2"
                        style={{ fontSize: '0.75rem' }}
                        onClick={() => handleDelete(cat.id)}>✕</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
